40	function applyRatioIf(
41	  condition: boolean,
42	  basePrice: number,
43	  numerator: number,
44	  denominator: number
45	): number {
46	  return condition ? (basePrice * numerator) / denominator : basePrice;
47	}
48	
49	function applyCursedSurcharge(items: { cursed: boolean }[], basePrice: number): number {
50	  const hasCursed = items.some((item) => item.cursed);
51	  return applyRatioIf(hasCursed, basePrice, 3, 2);
52	}
53	
54	function applyEnchantedSurcharge(items: { enchantment: number }[], basePrice: number): number {
55	  const hasHighEnchant = items.some((item) => item.enchantment >= 5);
56	  return applyRatioIf(hasHighEnchant, basePrice, 13, 10);
57	}
58	
59	function applyLoyaltyDiscount(yearsWithMHPCO: number, basePrice: number): number {
60	  return applyRatioIf(yearsWithMHPCO >= 2, basePrice, 8, 10);
61	}
