63	export function runScenario(scenario: any): unknown {
64	  const results: { premium: number }[] = [];
65	  let quoteCount = 0;
66	  for (const step of scenario.steps) {
67	    const items = step.items;
68	    const basePrice = quoteBasePrice(items);
69	    const withCursed = applyCursedSurcharge(items, basePrice);
70	    const withEnchanted = applyEnchantedSurcharge(items, withCursed);
71	    const withLoyalty = applyLoyaltyDiscount(scenario.customer.yearsWithMHPCO, withEnchanted);
72	    const withContractAdjustment =
73	      quoteCount === 0
74	        ? applyFirstInsuranceSurcharge(withLoyalty)
75	        : Math.ceil((withLoyalty * 85) / 100);
76	    const premium = withContractAdjustment + FIXED_FEE;
77	    results.push({ premium });
78	    quoteCount++;
79	  }
80	  return { results };
81	}
